class Solution {
public:
    int findTheLongestBalancedSubstring(string s) {
        int n = s.size(), res = 0;
        for (int i = 0; i < n; i++) {
            int cnt0 = 0, cnt1 = 0;
            for (int j = i; j < n; j++) {
                if (s[j] == '0') cnt0++;
                else if (s[j] == '1' && cnt0 > 0) cnt1++;
                if (cnt0 == cnt1) res = max(res, cnt0 + cnt1);
                if (cnt1 > cnt0) break;
            }
        }
        return res;
    }
};

